  return (
    <motion.div className="flex justify-start mb-3" initial={{opacity:0,y:10}} animate={{opacity:1,y:0}}>
      <div className="bg-surface px-3 py-2 rounded-2xl rounded-bl-md">
        <PenguinLoading message="분석 중이에요..." />
      </div>
    </motion.div>
  );
}


